#include <stdio.h>
int main() {
    int T, N, Bi, sum;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        sum = 0;
        for (int i = 0; i < N; i++) {
            scanf("%d", &Bi);
            sum += Bi;
        }
        if (sum <= 100) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

