import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int sum = 0;
            for (int i = 0; i < N; i++) {
                int Bi = sc.nextInt();
                sum += Bi;
            }
            if (sum <= 100) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
}

